using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_ea27109b0c074809a6339039091c8b27.Auth;

/// <summary>
/// Server-side provider that creates a hardcoded authenticated user and
/// persists the claims into PersistentComponentState so the WebAssembly
/// runtime can restore them after the interactive handoff.
/// </summary>
public sealed class FakeAuthenticationStateProvider
    : ServerAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public FakeAuthenticationStateProvider(PersistentComponentState state)
    {
        _state = state;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);

        // Build a hardcoded identity for "bob@example.com"
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Fake");
        var user = new ClaimsPrincipal(identity);

        SetAuthenticationState(Task.FromResult(new AuthenticationState(user)));
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        if (_authStateTask is null) return;

        var authState = await _authStateTask;
        var principal = authState.User;
        if (principal.Identity?.IsAuthenticated != true) return;

        // Persist every claim as a simple serializable list
        var claims = principal.Claims.Select(c => new ClaimData(c.Type, c.Value)).ToList();
        _state.PersistAsJson(nameof(ClaimData), claims);
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

/// <summary>Lightweight DTO for serializing claims across render modes.</summary>
public sealed record ClaimData(string Type, string Value);

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_ea27109b0c074809a6339039091c8b27.Client.Auth;

/// <summary>
/// Client-side (WebAssembly) provider that restores the authenticated user
/// from claims persisted by the server during prerendering.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (state.TryTakeFromJson<List<ClaimData>>(nameof(ClaimData), out var claims)
            && claims is { Count: > 0 })
        {
            var identity = new ClaimsIdentity(
                claims.Select(c => new Claim(c.Type, c.Value)),
                authenticationType: "Fake");

            _authStateTask = Task.FromResult(
                new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

/// <summary>Lightweight DTO matching the server-side serialization.</summary>
public sealed record ClaimData(string Type, string Value);

